import React from 'react';

/**
 * StatusBadge Component
 * Displays complaint status with appropriate colors
 */
const StatusBadge = ({ status, className = '' }) => {
  // Status to color mapping
  const statusStyles = {
    open: {
      bg: 'bg-blue-100',
      text: 'text-blue-700',
      label: 'Open',
      icon: '📋',
    },
    assigned: {
      bg: 'bg-yellow-100',
      text: 'text-yellow-700',
      label: 'Assigned',
      icon: '👤',
    },
    in_progress: {
      bg: 'bg-purple-100',
      text: 'text-purple-700',
      label: 'In Progress',
      icon: '⚙️',
    },
    resolved: {
      bg: 'bg-emerald-100',
      text: 'text-emerald-700',
      label: 'Resolved',
      icon: '✅',
    },
    closed: {
      bg: 'bg-slate-100',
      text: 'text-slate-700',
      label: 'Closed',
      icon: '🔒',
    },
    reopened: {
      bg: 'bg-orange-100',
      text: 'text-orange-700',
      label: 'Reopened',
      icon: '🔄',
    },
  };

  const style = statusStyles[status] || statusStyles.open;

  return (
    <span
      className={`px-3 py-1.5 rounded-full font-semibold text-sm whitespace-nowrap inline-flex items-center gap-1 ${style.bg} ${style.text} ${className}`}
    >
      <span>{style.icon}</span>
      <span>{style.label}</span>
    </span>
  );
};

export default StatusBadge;
